+        let summary = summarize_room(
+            "!room:matrix.org",
+            "join",
+            &[Event {
+                event_id: Some("$member2".into()),
+                r#type: "m.room.member".into(),
+                state_key: Some("@bob:matrix.org".into()),
+                sender: Some("@bob:matrix.org".into()),
+                origin_server_ts: Some(200),
